var findDuplicates = function(nums) {
    const res = [];
    for (const x of nums) {
        const a = Math.abs(x);
        if (nums[a - 1] < 0) {
            res.push(a);
        } else {
            nums[a - 1] = -nums[a - 1];
        }
    }
    return res;
};
